    private fun ASTNode.exceedsMaxLineLengthWhenWrappedInNullableType(): Boolean {
        require(elementType == VALUE_PARAMETER_LIST)
        // When a function type is wrapped in a nullable type, the nullable type is wrapped first. Determine whether the
        // parameter list would still exceed the max line length after it is moved to the next line.
        val nullableType =
            generateSequence(treeParent) { it.treeParent }
                .firstOrNull { it.elementType == NULLABLE_TYPE }
                ?: return exceedsMaxLineLength()

        val indentText = indentConfig.childIndentOf(nullableType)
        val indentWidthInSpaces = indentConfig.toNormalizedIndent(indentText).replace("\t", " ".repeat(indentConfig.tabWidth)).length
        return (indentWidthInSpaces + textLength) > maxLineLength && !textContains('\n')
    }
